diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..894a471f6749 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3065,6 +3065,7 @@ static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
                             !IsAndVariant ? SelInner : InnerSel.FalseVal);
 }

+
 Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -3251,6 +3252,66 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
         if (auto *V = foldAndOrOfICmps(ICmp0, ICmp1, SI, IsAnd,
                                        /* IsLogical */ true))
           return replaceInstUsesWith(SI, V);
+
+    // Handle: select (A && B), C, false -> select A, (B && C), false
+    // if B && C can be simplified.
+    // We check if CondVal is a logical AND (select A, B, false).
+    if (IsAnd && match(CondVal, m_LogicalAnd(m_Value(A), m_Value(B))) &&
+        CondVal->hasOneUse()) {
+      // A && B && C.
+      // Try to fold B && C.
+      if (auto *BI = dyn_cast<ICmpInst>(B)) {
+        if (auto *CI = dyn_cast<ICmpInst>(Op1)) {
+          if (Value *V = foldAndOrOfICmps(BI, CI, SI, IsAnd, true)) {
+            if (isa<SelectInst>(CondVal))
+              return SelectInst::Create(A, V, Zero);
+            else
+              return BinaryOperator::CreateAnd(A, V);
+          }
+        }
+      }
+      // Try to fold A && C.
+      if (auto *AI = dyn_cast<ICmpInst>(A)) {
+        if (auto *CI = dyn_cast<ICmpInst>(Op1)) {
+          if (Value *V = foldAndOrOfICmps(AI, CI, SI, IsAnd, true)) {
+            if (isa<SelectInst>(CondVal))
+              return SelectInst::Create(B, V, Zero);
+            else
+              return BinaryOperator::CreateAnd(B, V);
+          }
+        }
+      }
+    }
+
+    // Handle: select (A || B), C, true -> select A, true, (B || C)
+    // if B || C can be simplified.
+    // We check if CondVal is a logical OR (select A, true, B).
+    if (!IsAnd && match(CondVal, m_LogicalOr(m_Value(A), m_Value(B))) &&
+        CondVal->hasOneUse()) {
+      // A || B || C.
+      // Try to fold B || C.
+      if (auto *BI = dyn_cast<ICmpInst>(B)) {
+        if (auto *CI = dyn_cast<ICmpInst>(Op1)) {
+          if (Value *V = foldAndOrOfICmps(BI, CI, SI, IsAnd, true)) {
+            if (isa<SelectInst>(CondVal))
+              return SelectInst::Create(A, One, V);
+            else
+              return BinaryOperator::CreateOr(A, V);
+          }
+        }
+      }
+      // Try to fold A || C.
+      if (auto *AI = dyn_cast<ICmpInst>(A)) {
+        if (auto *CI = dyn_cast<ICmpInst>(Op1)) {
+          if (Value *V = foldAndOrOfICmps(AI, CI, SI, IsAnd, true)) {
+            if (isa<SelectInst>(CondVal))
+              return SelectInst::Create(B, One, V);
+            else
+              return BinaryOperator::CreateOr(B, V);
+          }
+        }
+      }
+    }
   }

   // select (a || b), c, false -> select a, c, false
@@ -3323,6 +3384,7 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   return nullptr;
 }

+
 // Return true if we can safely remove the select instruction for std::bit_ceil
 // pattern.
 static bool isSafeToRemoveBitCeilSelect(ICmpInst::Predicate Pred, Value *Cond0,

